<?php $__env->startSection('title','Order Details'); ?>
<?php $__env->startSection('content'); ?><div class="row g-4"><div class="col-lg-8"><div class="table-card"><h4><?php echo e($order->order_number); ?></h4><table class="table"><tr><th>Product</th><th>Qty</th><th>Total</th></tr><?php $__currentLoopData = $order->items; $__env->addLoop($__currentLoopData); foreach($__currentLoopData as $item): $__env->incrementLoopIndices(); $loop = $__env->getLastLoop(); ?><tr><td><?php echo e($item->product_name); ?></td><td><?php echo e($item->quantity); ?></td><td>৳<?php echo e(number_format($item->total_price,2)); ?></td></tr><?php endforeach; $__env->popLoop(); $loop = $__env->getLastLoop(); ?></table><a class="btn btn-outline-secondary" href="<?php echo e(route('admin.orders.invoice',$order)); ?>">Print Invoice</a></div></div><div class="col-lg-4"><div class="table-card"><form method="post" action="<?php echo e(route('admin.orders.status',$order)); ?>"><?php echo csrf_field(); ?> <?php echo method_field('PATCH'); ?><label>Status</label><select class="form-select mb-3" name="status"><?php $__currentLoopData = ['pending','confirmed','processing','shipped','delivered','cancelled']; $__env->addLoop($__currentLoopData); foreach($__currentLoopData as $status): $__env->incrementLoopIndices(); $loop = $__env->getLastLoop(); ?><option <?php if($order->status==$status): echo 'selected'; endif; ?>><?php echo e($status); ?></option><?php endforeach; $__env->popLoop(); $loop = $__env->getLastLoop(); ?></select><button class="btn btn-primary">Update</button></form><hr><p><?php echo e($order->shippingAddress->address_line); ?>, <?php echo e($order->shippingAddress->city); ?></p><h4>Total ৳<?php echo e(number_format($order->total_amount,2)); ?></h4></div></div></div><?php $__env->stopSection(); ?>

